  <div class="hcD" style="left:30mm;top:26mm;">
    <div class="hcI">
      <div class="hls ps24" style="line-height:3.93mm;white-space:nowrap;left:0mm;top:-0.24mm;height:4.76mm;width:159.99mm;">
        <div class="htb" style="left:0.50mm;width:14.50mm;top:0.06mm;height:4.70mm;display:inline-block;position:relative;vertical-align:middle;">
          <svg class="hs" viewBox="-2.50 -2.50 19.50 9.70" style="left:-2.50mm;top:-2.50mm;width:19.50mm;height:9.70mm;">
            <path d="M0,0 L0,4.70" style="stroke:#0000FF;stroke-linecap:butt;stroke-width:0.70;"></path>
