      <div class="hls ps3" style="line-height:2.63mm;white-space:nowrap;left:10.58mm;top:45.95mm;height:3.35mm;width:149.41mm;"><span class="hrt cs3">①</span><span class="hrt cs3">꿈</span><span class="htC" style="left:0.84mm;width:65.76mm;height:100%;"></span><span class="hrt cs3">②</span><span class="hrt cs3">희망</span></div>
      <div class="hls ps3" style="line-height:2.63mm;white-space:nowrap;left:10.58mm;top:51.31mm;height:3.35mm;width:149.41mm;"><span class="hrt cs3">③</span><span class="hrt cs3">환상</span><span class="htC" style="left:0.84mm;width:62.86mm;height:100%;"></span><span class="hrt cs3">④</span><span class="hrt cs3">야망</span></div>
      <div class="hls ps3" style="line-height:2.63mm;white-space:nowrap;left:10.58mm;top:56.66mm;height:3.35mm;width:149.41mm;"><span class="hrt cs3">⑤</span><span class="hrt cs3">염원</span></div>
      <div class="hls ps37" style="line-height:2.79mm;white-space:nowrap;left:0mm;top:62.01mm;height:3.53mm;width:159.99mm;"></div>
