      <div class="hls ps3" style="line-height:7.26mm;white-space:nowrap;left:10.58mm;top:32.77mm;height:7.94mm;width:149.41mm;"><span class="hrt cs3">③</span>
        <div class="heq" style="width:4.01mm;height:7.94mm;background-repeat:no-repeat;background-image:url('2편 최신기출문제 (46-143)_html_1224_hd108.png');display:inline-block;position:relative;vertical-align:middle;"></div>
